package ua.university.sms.exception;import org.springframework.http.*;import org.springframework.web.bind.MethodArgumentNotValidException;import org.springframework.web.bind.annotation.*;import java.time.*;import java.util.*;
@ControllerAdvice public class GlobalExceptionHandler{@ExceptionHandler(NotFoundException.class) ResponseEntity<?> nf(NotFoundException e){return err(HttpStatus.NOT_FOUND,e.getMessage());}@ExceptionHandler({IllegalArgumentException.class,IllegalStateException.class}) ResponseEntity<?> bad(RuntimeException e){return err(HttpStatus.BAD_REQUEST,e.getMessage());}@ExceptionHandler(MethodArgumentNotValidException.class) ResponseEntity<?> validation(MethodArgumentNotValidException e){return err(HttpStatus.BAD_REQUEST,e.getBindingResult().getFieldErrors().stream().map(f->f.getField()+": "+f.getDefaultMessage()).toList().toString());}private ResponseEntity<Map<String,Object>> err(HttpStatus s,String m){return ResponseEntity.status(s).body(Map.of("timestamp",Instant.now().toString(),"status",s.value(),"error",s.getReasonPhrase(),"message",m));}}
